#include <bits/stdc++.h>
using namespace std;
struct S{string n;int k,e,m;};
int main(){int n;scanf("%d",&n);vector<S>v(n);for(auto&s:v){char b[16];scanf("%s %d %d %d",b,&s.k,&s.e,&s.m);s.n=b;}sort(v.begin(),v.end(),[](const S&a,const S&b){if(a.k!=b.k)return a.k>b.k;if(a.e!=b.e)return a.e<b.e;if(a.m!=b.m)return a.m>b.m;return a.n<b.n;});string out;for(auto&s:v){out+=s.n;out+='\n';}fputs(out.c_str(),stdout);}
